import React, { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { 
  GraduationCap, 
  Menu, 
  X
} from 'lucide-react';

interface LayoutProps {
  onOpenEligibility: () => void;
  onOpenLeadMagnet: () => void;
}

const Layout: React.FC<LayoutProps> = ({ onOpenEligibility, onOpenLeadMagnet }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  const isActive = (path: string) => {
    return location.pathname === path ? "text-promarch-green font-bold" : "text-gray-600 hover:text-promarch-green font-medium";
  };

  return (
    <div className="flex flex-col min-h-screen font-sans text-gray-900">
      {/* Navigation */}
      <nav className="fixed w-full bg-white/95 backdrop-blur-sm shadow-sm z-40 transition-all">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <Link to="/" className="flex items-center gap-2" onClick={closeMenu}>
              <div className="bg-promarch-green p-2 rounded-lg">
                <GraduationCap className="text-white w-6 h-6" />
              </div>
              <div className="leading-tight">
                <h1 className="text-xl font-bold text-promarch-blue">PROMARCH</h1>
                <span className="text-xs font-medium text-promarch-green tracking-wider">CAREER ABROAD</span>
              </div>
            </Link>

            {/* Desktop Menu */}
            <div className="hidden md:flex space-x-8 items-center">
              <Link to="/" className={isActive("/")}>Home</Link>
              <Link to="/about" className={isActive("/about")}>About Us</Link>
              <Link to="/services" className={isActive("/services")}>Services</Link>
              <button 
                onClick={onOpenEligibility}
                className="bg-promarch-green text-white px-6 py-2.5 rounded-full font-semibold hover:bg-emerald-800 transition-all shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
              >
                Check Eligibility
              </button>
            </div>

            {/* Mobile Menu Button */}
            <div className="md:hidden">
              <button onClick={toggleMenu} className="text-gray-600 hover:text-promarch-green">
                {isMenuOpen ? <X className="w-7 h-7" /> : <Menu className="w-7 h-7" />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMenuOpen && (
          <div className="md:hidden bg-white border-t border-gray-100 animate-fade-in">
            <div className="px-4 pt-2 pb-6 space-y-2">
              <Link to="/" onClick={closeMenu} className="block w-full text-left px-3 py-3 text-gray-600 font-medium">Home</Link>
              <Link to="/about" onClick={closeMenu} className="block w-full text-left px-3 py-3 text-gray-600 font-medium">About Us</Link>
              <Link to="/services" onClick={closeMenu} className="block w-full text-left px-3 py-3 text-gray-600 font-medium">Services</Link>
              <button 
                onClick={() => { onOpenEligibility(); closeMenu(); }}
                className="block w-full text-center mt-4 bg-promarch-green text-white px-3 py-3 rounded-lg font-semibold"
              >
                Check Eligibility
              </button>
            </div>
          </div>
        )}
      </nav>

      {/* Page Content */}
      <main className="flex-grow pt-20">
        <Outlet context={{ openEligibility: onOpenEligibility, openLeadMagnet: onOpenLeadMagnet }} />
      </main>

      {/* Simplified Footer */}
      <footer className="bg-gray-900 text-gray-400 py-8 border-t border-gray-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-2">
             <GraduationCap className="text-white w-5 h-5" />
             <span className="text-md font-bold text-white">PROMARCH</span>
          </div>
          <div className="text-sm">
            &copy; {new Date().getFullYear()} Promarch Career Abroad.
          </div>
        </div>
      </footer>
    </div>
  );
};

export default Layout;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '40px', color: '#B91C1C', textAlign: 'center', fontFamily: 'sans-serif', maxWidth: '600px', margin: '0 auto' }}>
          <h2 style={{ fontSize: '24px', marginBottom: '16px' }}>Application Error</h2>
          <p style={{ color: '#4B5563', marginBottom: '20px' }}>We encountered an issue while loading Promarch Career Abroad.</p>
          <div style={{ background: '#F3F4F6', padding: '16px', borderRadius: '8px', overflow: 'auto', textAlign: 'left', fontSize: '14px' }}>
            {this.state.error?.message}
          </div>
          <button 
            onClick={() => window.location.reload()}
            style={{ marginTop: '20px', padding: '10px 20px', backgroundColor: '#047857', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold' }}
          >
            Refresh Page
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <React.StrictMode>
      <ErrorBoundary>
        <App />
      </ErrorBoundary>
    </React.StrictMode>
  );
} else {
  console.error("Failed to find the root element");
}

